from flask import Flask, jsonify, make_response, request
from flask_jwt_extended import (
    JWTManager, jwt_required, create_access_token, get_raw_jwt
)
import datetime

app = Flask(__name__)
# Setup the Flask-JWT-Extended extension
app.config['JWT_SECRET_KEY'] = 'super-secret'  # Change this!
jwt = JWTManager(app)

@app.route('/login', methods=['POST'])
def login():
    if not request.is_json:
        return jsonify({"msg": "Missing JSON in request"}), 400
    
    username = request.json.get('username', None)
    password = request.json.get('password', None)
    
    # Here you should check your database for user credentials
    if not username:
        return jsonify({"msg": "Missing username parameter"}), 400
    if not password:
        return jsonify({"msg": "Missing password parameter"}), 400

    # As we're just testing, here I'm assuming that a user exists and the password is correct
    access_token = create_access_token(identity=username)
    return jsonify(access_token=access_token), 200

@app.route('/protected', methods=['GET'])
@jwt_required
def protected():
    # Access the identity of the current user with get_raw_jwt()['identity']
    return jsonify({"msg": f"Hello, {get_raw_jwt()['identity']}"}), 200

if __name__ == '__main__':
    app.run(port=5000)